Javascript.transformToDisplay:
var description = Services.getValue( REF_DATA_XPATH + "/HearingAttendeesList/HearingAttendee[./Value = " + HearingAttendees.dataBinding + "]/Description" );
if (description != null)
{
	return description;
}
else
{
	return value;
}

Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/HearingAttendeesList/HearingAttendee[./Value = " + HearingAttendees.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/HearingAttendeesList/HearingAttendee[./Description = " + HearingAttendees.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

Javascript.miscCode:

HearingAttendees.initialise		= function() 
{ 
	dom = getList("../LOV/HearingAttendeesList.xml"); 
	Services.addNode(dom, REF_DATA_XPATH);			
	return false; 
}

//HearingAttendees.srcData 		= REF_DATA_XPATH + "/HearingAttendeesList";
//HearingAttendees.rowXPath 		= "HearingAttendee";
//HearingAttendees.keyXPath 		= "Description";

function HearingAttendeesLOVGrid() {};
HearingAttendeesLOVGrid.dataBinding = HearingAttendees.dataBinding;
HearingAttendeesLOVGrid.srcData = REF_DATA_XPATH + "/HearingAttendeesList";
HearingAttendeesLOVGrid.rowXPath = "HearingAttendee";
HearingAttendeesLOVGrid.keyXPath = "Description";
HearingAttendeesLOVGrid.columns = [
	{xpath: "Description"}
];
HearingAttendeesLOVGrid.raise = {
	eventBinding: {
		singleClicks: [ {element: "HearingAttendeesLOVButton"} ],
		keys: [ { key: Key.F6, element: "HearingAttendees" } ]
	}
};

function HearingAttendeesLOVButton() {}
HearingAttendeesLOVButton.tabIndex = __tabIdx++;
